#include<bits/stdc++.h>
using namespace std;

/*
Consider we fix a vertex through which our path goes through -> U
Cost of walk will be: dist(U, S) + dist(U, T) + dist(U, V) 
To minimise the above equation, we will consider all such vertices U
We will need to compute dijkstra from 3 sources -> S, T, V
*/

const int N = 1e5 + 1;
const long long INF = 1e18;

long long d[3][N]; // d[0] stores min distance from S, d[1] from T, d[2] from V
vector<pair<int,int>> adj[N];
bool vis[N];


void dijkstra(int source, int n, int idx) {
    for(int i = 1; i <= n; i++) {
        d[idx][i] = INF, vis[i] = false;
    }
    d[idx][source] = 0;
    priority_queue<pair<long long, int>> pq;
    pq.push({0, source});
    while(pq.size() != 0) {
        pair<long long, int> node = pq.top();
        pq.pop();
        int v = node.second;
        long long distance = node.first;
        if(vis[v]) {
            continue;
        }
        vis[v] = 1;
        for(auto edge: adj[v]) {
            int u = edge.first;
            int weight = edge.second;
            d[idx][u] = min(d[idx][u], d[idx][v] + weight);
            pq.push({-d[idx][u], u}); 
        }
    }      
}

int main() {
    int t; cin >> t;
    while(t--) {
        int n, m; cin >> n >> m;
        int S, T, V; cin >> S >> T >> V;
        for(int i = 1; i <= n; i++) {
            adj[i].clear(); // resetting the adjacency list
        }
        for(int i = 1; i <= m; i++) {
            int x, y, w; cin >> x >> y >> w;
            // Undirected graph
            adj[x].push_back({y, w});
            adj[y].push_back({x, w});
        }

        dijkstra(S, n, 0); // S as source
        dijkstra(T, n, 1); // T as source
        dijkstra(V, n, 2); // V as source

        long long ans = INF;

        for(int u = 1; u <= n; u++) { // Fixing a vertex u
            long long res = d[0][u] + d[1][u] + d[2][u];
            ans = min(ans, res);
        }

        cout << ans << "\n";
    }
    return 0;
}

