#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#include <limits.h>

#define N 100001
#define INF 1000000000000000000LL

typedef struct {
    int vertex;
    long long distance;
} Node;

typedef struct {
    Node *nodes;
    int size;
} MinHeap;

long long d[3][N]; // d[0] stores min distance from S, d[1] from T, d[2] from V
int **adj;
int *adj_size;
bool *vis;

// Function to create a new MinHeap node
Node newNode(int vertex, long long distance) {
    Node node;
    node.vertex = vertex;
    node.distance = distance;
    return node;
}

// Function to create a MinHeap
MinHeap* createMinHeap(int capacity) {
    MinHeap* minHeap = (MinHeap*) malloc(sizeof(MinHeap));
    minHeap->nodes = (Node*) malloc(capacity * sizeof(Node));
    minHeap->size = 0;
    return minHeap;
}

// Function to swap two nodes of the MinHeap
void swapNode(Node *a, Node *b) {
    Node t = *a;
    *a = *b;
    *b = t;
}

// Heapify function
void heapify(MinHeap* minHeap, int idx) {
    int smallest = idx;
    int left = 2 * idx + 1;
    int right = 2 * idx + 2;

    if (left < minHeap->size && minHeap->nodes[left].distance < minHeap->nodes[smallest].distance)
        smallest = left;

    if (right < minHeap->size && minHeap->nodes[right].distance < minHeap->nodes[smallest].distance)
        smallest = right;

    if (smallest != idx) {
        swapNode(&minHeap->nodes[smallest], &minHeap->nodes[idx]);
        heapify(minHeap, smallest);
    }
}

// Function to check if the heap is empty
bool isEmpty(MinHeap* minHeap) {
    return minHeap->size == 0;
}

// Extract the node with minimum distance value
Node extractMin(MinHeap* minHeap) {
    if (isEmpty(minHeap))
        return newNode(-1, INF);

    Node root = minHeap->nodes[0];
    Node lastNode = minHeap->nodes[minHeap->size - 1];
    minHeap->nodes[0] = lastNode;
    minHeap->size--;
    heapify(minHeap, 0);
    return root;
}

// Function to insert a new node to the heap
void insertMinHeap(MinHeap* minHeap, Node node) {
    minHeap->size++;
    int i = minHeap->size - 1;
    minHeap->nodes[i] = node;

    while (i && minHeap->nodes[i].distance < minHeap->nodes[(i - 1) / 2].distance) {
        swapNode(&minHeap->nodes[i], &minHeap->nodes[(i - 1) / 2]);
        i = (i - 1) / 2;
    }
}

// Function to add an edge
void add_edge(int u, int v, int weight) {
    adj[u][adj_size[u]] = v;
    adj[u][adj_size[u] + 1] = weight;
    adj_size[u] += 2;
}

void dijkstra(int source, int n, int idx) {
    for (int i = 1; i <= n; i++) {
        d[idx][i] = INF;
        vis[i] = false;
    }
    d[idx][source] = 0;

    MinHeap* minHeap = createMinHeap(N);
    insertMinHeap(minHeap, newNode(source, 0));

    while (!isEmpty(minHeap)) {
        Node minNode = extractMin(minHeap);
        int v = minNode.vertex;

        if (vis[v]) continue;
        vis[v] = true;

        for (int k = 0; k < adj_size[v]; k += 2) {
            int u = adj[v][k];
            int weight = adj[v][k + 1];
            if (d[idx][u] > weight + d[idx][v]) {
                d[idx][u] = weight + d[idx][v];
                insertMinHeap(minHeap, newNode(u, d[idx][u]));
            }
        }
    }
    free(minHeap->nodes);
    free(minHeap);
}

int main() {
    int t;
    scanf("%d", &t);

    adj = (int **)malloc(N * sizeof(int *));
    adj_size = (int *)malloc(N * sizeof(int));
    vis = (bool *)malloc(N * sizeof(bool));

    for (int i = 0; i < N; i++) {
        adj[i] = (int *)malloc(2 * N * sizeof(int)); // Allocate enough space for edges
        adj_size[i] = 0;
    }

    while (t--) {
        int n, m;
        scanf("%d %d", &n, &m);
        int S, T, V;
        scanf("%d %d %d", &S, &T, &V);

        for (int i = 1; i <= n; i++) {
            adj_size[i] = 0;
        }

        for (int i = 0; i < m; i++) {
            int x, y, w;
            scanf("%d %d %d", &x, &y, &w);

            // Undirected edge
            add_edge(x, y, w);
            add_edge(y, x, w);
        }

        dijkstra(S, n, 0); // S as source
        dijkstra(T, n, 1); // T as source
        dijkstra(V, n, 2); // V as source

        long long ans = INF;

        for (int u = 1; u <= n; u++) { // Fixing a vertex u
            long long res = d[0][u] + d[1][u] + d[2][u];
            if (res < ans) ans = res;
        }

        printf("%lld\n", ans);
    }

    for (int i = 0; i < N; i++) {
        free(adj[i]);
    }
    free(adj);
    free(adj_size);
    free(vis);

    return 0;
}

