Cost of walk will be: dist(U, S) + dist(U, T) + dist(U, V) 
To minimise the above equation, we will consider all such vertices U
We will need to compute dijkstra from 3 sources -> S, T, V
*/

class main {
    static final int N = 100001;
    static final long INF = (long)1e18;
    static long[][] d = new long[3][N]; // d[0] stores min distance from S, d[1] from T, d[2] from V
    static List<Pair>[] adj = new ArrayList[N];
    static boolean[] vis = new boolean[N];

    static class Pair {
        int node;
        long weight;

        Pair(int node, long weight) {
            this.node = node;
            this.weight = weight;
        }
    }

    static void dijkstra(int source, int n, int idx) {
        for (int i = 1; i <= n; i++) {
            d[idx][i] = INF;
            vis[i] = false;
        }
        d[idx][source] = 0;
        PriorityQueue<Pair> pq = new PriorityQueue<>((a, b) -> Long.compare(a.weight, b.weight));
        pq.add(new Pair(source, 0));

        while (!pq.isEmpty()) {
            Pair node = pq.poll();

            int v = node.node;
            long distance = node.weight;

            if (vis[v]) {
                continue;
            }
            vis[v] = true;

            for (Pair edge : adj[v]) {
                int u = edge.node;
                long weight = edge.weight;
                d[idx][u] = Math.min(d[idx][u], d[idx][v] + weight);
                pq.add(new Pair(u, d[idx][u]));
            }
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int t = scanner.nextInt();

        while (t-- > 0) {
            int n = scanner.nextInt();
            int m = scanner.nextInt();
            int S = scanner.nextInt();
            int T = scanner.nextInt();
            int V = scanner.nextInt();

            for (int i = 1; i <= n; i++) {
                adj[i] = new ArrayList<>();
            }

            for (int i = 0; i < m; i++) {
                int x = scanner.nextInt();
                int y = scanner.nextInt();
                int w = scanner.nextInt();
                // Undirected graph
                adj[x].add(new Pair(y, w));
                adj[y].add(new Pair(x, w));
            }

            dijkstra(S, n, 0); // S as source
            dijkstra(T, n, 1); // T as source
            dijkstra(V, n, 2); // V as source

            long ans = INF;

            for (int u = 1; u <= n; u++) { // Fixing a vertex u
                long res = d[0][u] + d[1][u] + d[2][u];
                ans = Math.min(ans, res);
            }

            System.out.println(ans);
        }
        scanner.close();
    }
}

