const fs = require('fs');

function solve() {
    // Fast I/O setup using Buffer (Required for large I/O in competitive programming)
    const buffer = fs.readFileSync(0);
    let offset = 0;

    function readInt() {
        while (offset < buffer.length && buffer[offset] <= 32) offset++;
        if (offset >= buffer.length) return null;
        let res = 0;
        while (offset < buffer.length && buffer[offset] > 32) {
            res = res * 10 + (buffer[offset] - 48);
            offset++;
        }
        return res;
    }

    // Read number of test cases
    let t = readInt();
    if (t === null) return;

    // Graph global allocations (reused across test cases to prevent Garbage Collection pauses)
    const MAXN = 100005;
    const MAXM = 200005; // 2 * M for undirected graph edges

    const head = new Int32Array(MAXN).fill(-1);
    const to = new Int32Array(MAXM);
    const nxt = new Int32Array(MAXM);
    const weight = new Int32Array(MAXM);

    // Custom Min-Heap tailored for Dijkstra's
    class MinHeap {
        constructor(maxSize) {
            this.node = new Int32Array(maxSize);
            this.dist = new Float64Array(maxSize);
            this.size = 0;
        }
        push(u, d) {
            let i = this.size++;
            let p;
            while (i > 0) {
                p = (i - 1) >> 1;
                if (this.dist[p] <= d) break;
                this.node[i] = this.node[p];
                this.dist[i] = this.dist[p];
                i = p;
            }
            this.node[i] = u;
            this.dist[i] = d;
        }
        remove() {
            this.size--;
            if (this.size > 0) {
                let u = this.node[this.size];
                let d = this.dist[this.size];
                let i = 0, half = this.size >> 1;
                while (i < half) {
                    let left = (i << 1) + 1;
                    let right = left + 1;
                    let best = (right < this.size && this.dist[right] < this.dist[left]) ? right : left;

                    if (this.dist[best] >= d) break;
                    this.node[i] = this.node[best];
                    this.dist[i] = this.dist[best];
                    i = best;
                }
                this.node[i] = u;
                this.dist[i] = d;
            }
        }
    }

    const pq = new MinHeap(MAXM * 2);
    const INF = 1e16; // Safe infinity well within Number.MAX_SAFE_INTEGER

    function dijkstra(start, n) {
        let dist = new Float64Array(n + 1).fill(INF);
        dist[start] = 0;
        pq.size = 0;
        pq.push(start, 0);

        while (pq.size > 0) {
            let u = pq.node[0];
            let d = pq.dist[0];
            pq.remove();

            if (d > dist[u]) continue;

            for (let e = head[u]; e !== -1; e = nxt[e]) {
                let v = to[e];
                let w = weight[e];
                if (dist[u] + w < dist[v]) {
                    dist[v] = dist[u] + w;
                    pq.push(v, dist[v]);
                }
            }
        }
        return dist;
    }

    let out = [];

    // Process all test cases
    while (t--) {
        let n = readInt();
        let m = readInt();
        let s = readInt();
        let target = readInt(); // T in the problem
        let v = readInt();

        // Reset adjacency array heads for current N nodes
        head.fill(-1, 0, n + 1);
        let edgeCount = 0;

        // Build Graph
        for (let i = 0; i < m; i++) {
            let a = readInt();
            let b = readInt();
            let c = readInt();

            to[edgeCount] = b;
            weight[edgeCount] = c;
            nxt[edgeCount] = head[a];
            head[a] = edgeCount++;

            to[edgeCount] = a;
            weight[edgeCount] = c;
            nxt[edgeCount] = head[b];
            head[b] = edgeCount++;
        }

        // Generate shortest path trees from the 3 terminal nodes
        let distS = dijkstra(s, n);
        let distT = dijkstra(target, n);
        let distV = dijkstra(v, n);

        // Find the optimal junction point (Steiner point)
        let minCost = INF;
        for (let i = 1; i <= n; i++) {
            let cost = distS[i] + distT[i] + distV[i];
            if (cost < minCost) {
